mapper.select:
SELECT ss.id, ss.student_id, ss.course_id, ss.semester_id, ss.usual_score, ss.midterm_score, ss.final_score, ss.total_score, ss.credit, ss.gpa, ss.status, ss.is_locked, ss.created_at, s.student_no, u.real_name as student_name, c.class_name, co.course_code, co.course_name, co.course_type, sem.semester_name FROM student_scores ss LEFT JOIN students s ON ss.student_id = s.id LEFT JOIN users u ON s.user_id = u.id LEFT JOIN classes c ON s.class_id = c.id LEFT JOIN courses co ON ss.course_id = co.id LEFT JOIN semesters sem ON ss.semester_id = sem.id WHERE ss.deleted = 0
AND u.real_name LIKE CONCAT('%', #{query.studentName}, '%')
AND s.student_no LIKE CONCAT('%', #{query.studentNo}, '%')
AND ss.course_id = #{query.courseId}
AND ss.semester_id = #{query.semesterId}
AND s.class_id = #{query.classId}
AND ss.status = #{query.status}
ORDER BY s.student_no, co.course_code

SELECT * FROM student_scores
WHERE student_id = #{studentId}
AND course_id = #{courseId}
AND semester_id = #{semesterId}
AND deleted = 0
LIMIT 1

SELECT COUNT(*) as total_count, AVG(ss.final_score) as avg_score, MAX(ss.final_score) as max_score, MIN(ss.final_score) as min_score, SUM(CASE WHEN ss.final_score >= 90 THEN 1 ELSE 0 END) as excellent_count, SUM(CASE WHEN ss.final_score >= 80 AND ss.final_score < 90 THEN 1 ELSE 0 END) as good_count, SUM(CASE WHEN ss.final_score >= 70 AND ss.final_score < 80 THEN 1 ELSE 0 END) as medium_count, SUM(CASE WHEN ss.final_score >= 60 AND ss.final_score < 70 THEN 1 ELSE 0 END) as pass_count, SUM(CASE WHEN ss.final_score < 60 THEN 1 ELSE 0 END) as fail_count FROM student_scores ss LEFT JOIN students s ON ss.student_id = s.id WHERE s.class_id = #{classId}
AND ss.course_id = #{courseId}
AND ss.semester_id = #{semesterId} AND ss.deleted = 0

SELECT COUNT(*) FROM student_scores
WHERE student_id = #{studentId}
AND semester_id = #{semesterId}
AND deleted = 0

mapper.update:
UPDATE student_scores
SET is_locked = 1, updated_at = NOW()
WHERE semester_id = #{semesterId}

    AND course_id = #{courseId}

AND deleted = 0

UPDATE student_scores
SET is_locked = 0, updated_at = NOW()
WHERE semester_id = #{semesterId}

    AND course_id = #{courseId}

AND deleted = 0
